import{_ as t,o as a,c as o,ai as r}from"./chunks/framework.BIXs0jTs.js";const l="/assets/preface-cover.Balx8Fq4.png",m=JSON.parse('{"title":"工程级 Prompt 设计","description":"","frontmatter":{"title":"工程级 Prompt 设计"},"headers":[],"relativePath":"10-claude-code/prompts.md","filePath":"10-claude-code/prompts.md","lastUpdated":null}'),i={name:"10-claude-code/prompts.md"};function s(n,e,p,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="第-4-章-工程级-prompt-设计-结构化与复用" tabindex="-1">第 4 章　工程级 Prompt 设计：结构化与复用 <a class="header-anchor" href="#第-4-章-工程级-prompt-设计-结构化与复用" aria-label="Permalink to &quot;第 4 章　工程级 Prompt 设计：结构化与复用&quot;">​</a></h1><p><img src="'+l+'" alt="工程级 Prompt 设计：结构化与复用"></p><p>提到 AI 编程，很多人第一反应是：“不就是把代码贴进去，然后问它怎么改吗？” 对于写个 Hello World 或者做道算法题，这当然没问题。但在复杂的工程环境中，随意的提问往往换来随意的回答——代码风格不统一、引入多余依赖、甚至破坏原有架构。</p><p>本章将教你如何写出<strong>工程级 Prompt</strong>。这种 Prompt 不再是随口一问的聊天，而是像写代码一样，有结构、有约束、可复用。</p><h2 id="_4-1-为什么你需要工程级-prompt" tabindex="-1">4.1 为什么你需要工程级 Prompt？ <a class="header-anchor" href="#_4-1-为什么你需要工程级-prompt" aria-label="Permalink to &quot;4.1 为什么你需要工程级 Prompt？&quot;">​</a></h2><p>在工程实战中，我们对 AI 的输出有三个核心要求：</p><ol><li><strong>准确性 (Precision)</strong>：不能幻觉，不能瞎编 API。</li><li><strong>一致性 (Consistency)</strong>：今天生成的代码和昨天生成的，风格应该一样。</li><li><strong>依从性 (Compliance)</strong>：必须遵守项目的 Lint 规则、命名规范和目录结构。</li></ol><p>随意的 Prompt（“帮我写个登录页面”）很难同时满足这三点。而工程级 Prompt 通过显式的上下文和约束，强迫 AI “戴着镣铐跳舞”，从而输出高质量的代码。</p><hr><h2 id="_4-2-prompt-的解剖学-四大要素" tabindex="-1">4.2 Prompt 的解剖学：四大要素 <a class="header-anchor" href="#_4-2-prompt-的解剖学-四大要素" aria-label="Permalink to &quot;4.2 Prompt 的解剖学：四大要素&quot;">​</a></h2><p>一个优秀的工程级 Prompt，通常包含以下四个部分（CRIC 模型）：</p><h3 id="_4-2-1-context-上下文" tabindex="-1">4.2.1 Context (上下文) <a class="header-anchor" href="#_4-2-1-context-上下文" aria-label="Permalink to &quot;4.2.1 Context (上下文)&quot;">​</a></h3><p>告诉 Claude 它在什么环境里工作。</p><ul><li><strong>角色设定</strong>：你是一个资深前端架构师 / Python 后端专家。</li><li><strong>技术栈</strong>：项目使用 React 18 + TypeScript + Tailwind CSS。</li><li><strong>业务背景</strong>：这是一个电商后台管理系统。</li></ul><h3 id="_4-2-2-request-任务目标" tabindex="-1">4.2.2 Request (任务目标) <a class="header-anchor" href="#_4-2-2-request-任务目标" aria-label="Permalink to &quot;4.2.2 Request (任务目标)&quot;">​</a></h3><p>清晰、原子化的指令。</p><ul><li>❌ “优化一下这个函数。”（太模糊）</li><li>✅ “重构 <code>calculateOrder</code> 函数，提取税费计算逻辑为独立函数，并添加 JSDoc 注释。”</li></ul><h3 id="_4-2-3-input-data-输入数据" tabindex="-1">4.2.3 Input Data (输入数据) <a class="header-anchor" href="#_4-2-3-input-data-输入数据" aria-label="Permalink to &quot;4.2.3 Input Data (输入数据)&quot;">​</a></h3><p>明确指出要处理哪些信息。</p><ul><li><strong>相关文件</strong>：<code>src/utils/tax.ts</code> 和 <code>src/types/order.ts</code>。</li><li><strong>参考代码</strong>：参考 <code>src/utils/currency.ts</code> 的写法。</li><li><strong>错误日志</strong>：粘贴具体的报错堆栈。</li></ul><h3 id="_4-2-4-constraints-约束条件" tabindex="-1">4.2.4 Constraints (约束条件) <a class="header-anchor" href="#_4-2-4-constraints-约束条件" aria-label="Permalink to &quot;4.2.4 Constraints (约束条件)&quot;">​</a></h3><p>这是最关键的部分，决定了输出是否“工程化”。</p><ul><li><strong>风格约束</strong>：使用函数式编程风格，禁止使用 <code>class</code>。</li><li><strong>依赖约束</strong>：只能使用现有的 <code>lodash</code>，不能引入新库。</li><li><strong>输出格式</strong>：只输出修改后的代码块，不要解释性文字。</li></ul><hr><h2 id="_4-3-常用-prompt-模板模式" tabindex="-1">4.3 常用 Prompt 模板模式 <a class="header-anchor" href="#_4-3-常用-prompt-模板模式" aria-label="Permalink to &quot;4.3 常用 Prompt 模板模式&quot;">​</a></h2><p>为了提高效率，我们可以总结出几种通用的 Prompt 模式。</p><h3 id="_4-3-1-修复者-模式-the-fixer" tabindex="-1">4.3.1 “修复者”模式 (The Fixer) <a class="header-anchor" href="#_4-3-1-修复者-模式-the-fixer" aria-label="Permalink to &quot;4.3.1 “修复者”模式 (The Fixer)&quot;">​</a></h3><p>用于修复 Bug 或错误。</p><blockquote><p><strong>模板</strong>： “作为 [角色]，请分析以下 [错误日志/现象]。 这里的 [相关代码] 似乎有问题。 请找出根本原因，并提供修复方案。 <strong>约束</strong>：保持原有函数签名不变；优先处理边界情况。”</p></blockquote><h3 id="_4-3-2-生成者-模式-the-generator" tabindex="-1">4.3.2 “生成者”模式 (The Generator) <a class="header-anchor" href="#_4-3-2-生成者-模式-the-generator" aria-label="Permalink to &quot;4.3.2 “生成者”模式 (The Generator)&quot;">​</a></h3><p>用于从零编写新功能。</p><blockquote><p><strong>模板</strong>： “请根据 [需求描述/接口定义]，实现 [功能模块]。 <strong>技术栈</strong>：[框架版本]。 <strong>约束</strong>：</p><ol><li>组件必须拆分为 Presentational 和 Container。</li><li>所有样式使用 Tailwind 类名。</li><li>包含基本的单元测试。”</li></ol></blockquote><h3 id="_4-3-3-审查者-模式-the-reviewer" tabindex="-1">4.3.3 “审查者”模式 (The Reviewer) <a class="header-anchor" href="#_4-3-3-审查者-模式-the-reviewer" aria-label="Permalink to &quot;4.3.3 “审查者”模式 (The Reviewer)&quot;">​</a></h3><p>用于代码审查和优化。</p><blockquote><p><strong>模板</strong>： “请审查以下代码 [粘贴代码]。 重点关注：</p><ol><li>安全性（如 SQL 注入、XSS）。</li><li>性能瓶颈。</li><li>代码可读性。 请以列表形式输出 Review 意见，按严重程度排序。”</li></ol></blockquote><hr><h2 id="_4-4-上下文管理技巧" tabindex="-1">4.4 上下文管理技巧 <a class="header-anchor" href="#_4-4-上下文管理技巧" aria-label="Permalink to &quot;4.4 上下文管理技巧&quot;">​</a></h2><p>在使用 Claude Code 时，如何高效地“喂”给它上下文是一门学问。</p><h3 id="_4-4-1-善用-file-或-read" tabindex="-1">4.4.1 善用 <code>@file</code> 或 <code>/read</code> <a class="header-anchor" href="#_4-4-1-善用-file-或-read" aria-label="Permalink to &quot;4.4.1 善用 `@file` 或 `/read`&quot;">​</a></h3><p>不要手动复制粘贴几十个文件的内容。</p><ul><li>使用 <code>claude &quot;...&quot; --file src/main.ts src/utils.ts</code></li><li>或者在交互模式下直接引用文件名，Claude Code 通常能自动读取。</li></ul><h3 id="_4-4-2-建立项目级-clauderc-概念性" tabindex="-1">4.4.2 建立项目级 <code>.clauderc</code> (概念性) <a class="header-anchor" href="#_4-4-2-建立项目级-clauderc-概念性" aria-label="Permalink to &quot;4.4.2 建立项目级 `.clauderc` (概念性)&quot;">​</a></h3><p>虽然 Claude Code 目前主要通过 Prompt 传递上下文，但你可以维护一个项目级的 <code>PROMPT_GUIDE.md</code> 文件，里面写满项目的核心规范。 每次开始复杂任务前，先让 Claude 读取这个文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Read PROMPT_GUIDE.md first, then help me refactor...&quot;</span></span></code></pre></div><p>这相当于给 Claude 加载了一个“项目特定的系统提示词”。</p><h3 id="_4-4-3-渐进式上下文" tabindex="-1">4.4.3 渐进式上下文 <a class="header-anchor" href="#_4-4-3-渐进式上下文" aria-label="Permalink to &quot;4.4.3 渐进式上下文&quot;">​</a></h3><p>不要一次性把整个仓库丢给它。</p><ol><li>先让它 <code>ls</code> 或 <code>tree</code> 看目录结构。</li><li>再让它读取核心配置文件（<code>package.json</code>, <code>go.mod</code>）了解依赖。</li><li>最后只读取与当前任务直接相关的 3-5 个源文件。</li></ol><hr><h2 id="_4-5-从-prompt-到-skill" tabindex="-1">4.5 从 Prompt 到 Skill <a class="header-anchor" href="#_4-5-从-prompt-到-skill" aria-label="Permalink to &quot;4.5 从 Prompt 到 Skill&quot;">​</a></h2><p>当你发现某个 Prompt 写得特别好，而且经常要用（比如“生成符合团队规范的 Commit Message”），你就应该把它升级为 <strong>Skill</strong>。</p><p>我们将在**下一部分（第 II 部分：Skill）**详细讲解如何把这些结构化的 Prompt 固化下来，变成团队可共享的工具。</p><blockquote><p><strong>思考题</strong>： 回顾你最近一次让 AI 写代码的经历，检查一下你的 Prompt 是否包含了 CRIC 四要素？如果加上缺失的要素，结果会有什么不同？</p></blockquote>',53)])])}const g=t(i,[["render",s]]);export{m as __pageData,g as default};
